"use client";
import * as React from "react";
import { tableAnatomy } from "@tessera/core";

export interface TableRootProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Zebra-stripes the body rows. */
  striped?: boolean;
  /** Highlights body rows on hover. */
  hoverable?: boolean;
}

function TableRoot({ striped, hoverable, children, ...rest }: TableRootProps) {
  return (
    <div
      {...tableAnatomy.attrs("root")}
      data-striped={striped || undefined}
      data-hoverable={hoverable || undefined}
      {...rest}
    >
      <table {...tableAnatomy.attrs("table")}>{children}</table>
    </div>
  );
}

function TableCaption(props: React.HTMLAttributes<HTMLTableCaptionElement>) {
  return <caption {...tableAnatomy.attrs("caption")} {...props} />;
}

function TableHeader(props: React.HTMLAttributes<HTMLTableSectionElement>) {
  return <thead {...tableAnatomy.attrs("header")} {...props} />;
}

function TableBody(props: React.HTMLAttributes<HTMLTableSectionElement>) {
  return <tbody {...tableAnatomy.attrs("body")} {...props} />;
}

function TableRow(props: React.HTMLAttributes<HTMLTableRowElement>) {
  return <tr {...tableAnatomy.attrs("row")} {...props} />;
}

function TableHead(props: React.ThHTMLAttributes<HTMLTableCellElement>) {
  return <th {...tableAnatomy.attrs("head")} scope="col" {...props} />;
}

function TableCell(props: React.TdHTMLAttributes<HTMLTableCellElement>) {
  return <td {...tableAnatomy.attrs("cell")} {...props} />;
}

export const Table = {
  Root: TableRoot,
  Caption: TableCaption,
  Header: TableHeader,
  Body: TableBody,
  Row: TableRow,
  Head: TableHead,
  Cell: TableCell,
};

@layer tessera.recipes {
  [data-scope="table"][data-part="root"] {
    width: 100%;
    overflow-x: auto;
    border: 1px solid var(--ts-border-muted);
    border-radius: var(--ts-radius-lg);
  }

  [data-scope="table"][data-part="table"] {
    width: 100%;
    border-collapse: collapse;
    font-size: var(--ts-font-size-sm);
    color: var(--ts-fg-default);
  }

  [data-scope="table"][data-part="caption"] {
    caption-side: bottom;
    padding: var(--ts-space-3);
    font-size: var(--ts-font-size-xs);
    color: var(--ts-fg-subtle);
    text-align: left;
  }

  [data-scope="table"][data-part="head"] {
    text-align: left;
    font-weight: var(--ts-font-weight-medium);
    font-size: var(--ts-font-size-xs);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--ts-fg-subtle);
    background: var(--ts-bg-surface);
    padding: var(--ts-space-3) var(--ts-space-4);
    border-bottom: 1px solid var(--ts-border-muted);
    white-space: nowrap;
  }

  [data-scope="table"][data-part="cell"] {
    padding: var(--ts-space-3) var(--ts-space-4);
    border-bottom: 1px solid var(--ts-border-muted);
    vertical-align: middle;
  }

  [data-scope="table"][data-part="body"] [data-part="row"]:last-child [data-part="cell"] {
    border-bottom: none;
  }

  [data-scope="table"][data-part="root"][data-striped]
    [data-part="body"]
    [data-part="row"]:nth-child(even) {
    background: var(--ts-bg-surface);
  }

  [data-scope="table"][data-part="root"][data-hoverable]
    [data-part="body"]
    [data-part="row"]:hover {
    background: var(--ts-bg-subtle);
  }
}
